        var _req = URLRequest(url: URL(string: _baseURL + "/fixtures/unicode_and_emoji_handling")!)
        _req.httpMethod = "POST"
        _req.setValue("application/json; charset=utf-8", forHTTPHeaderField: "Content-Type")
        _req.httpBody = "{\"description\":\"Best café in München 🇩🇪\",\"emoji_reactions\":\"👍❤️😂🎉\",\"name\":\"Coffee Shop ☕\",\"tags\":[\"食べ物\",\"音楽\",\"💰\"]}".data(using: .utf8)
        _req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        var response: HTTPURLResponse?
        var _responseData: Data?
        let _sema = DispatchSemaphore(value: 0)
        alefE2ESession.dataTask(with: _req) { data, resp, _ in
            response = resp as? HTTPURLResponse
            _responseData = data
            _sema.signal()
        }.resume()
        _sema.wait()
        let _resp = try XCTUnwrap(response)
        XCTAssertEqual(_resp.statusCode, 200)
        let _expected = try JSONSerialization.jsonObject(with: "{\"description\":\"Best café in München 🇩🇪\",\"emoji_reactions\":\"👍❤️😂🎉\",\"id\":1,\"name\":\"Coffee Shop ☕\",\"tags\":[\"食べ物\",\"音楽\",\"💰\"]}".data(using: .utf8)!)
        let _actual = try JSONSerialization.jsonObject(with: XCTUnwrap(_responseData))
        XCTAssertEqual(NSDictionary(dictionary: _expected as? [String: AnyHashable] ?? [:]), NSDictionary(dictionary: _actual as? [String: AnyHashable] ?? [:]))
    }

}
